const rows = $input.all().map((item) => item.json).filter((row) => String(row.tier).trim().toUpperCase() === 'B');
const scenarios = [
  { kind: 'interesado', reply_text: 'Hola, sí estamos interesados en avanzar con BNPL. Podemos agendar una llamada con nuestro CFO esta semana.' },
  { kind: 'objecion', reply_text: 'Nos interesa, pero hoy la objeción principal es el esfuerzo operativo de integración y el riesgo financiero. ¿Cómo lo manejan?' },
  { kind: 'opt_out', reply_text: 'Gracias, por ahora no estamos interesados. Preferimos no continuar con este contacto.' }
];

return scenarios.map((scenario, index) => {
  const row = rows[index];
  return {
    json: {
      ...row,
      scenario: scenario.kind,
      reply_text: scenario.reply_text,
      reply_date: new Date().toISOString(),
      contacto_nombre: ['María Rodríguez', 'Juan Pérez', 'Laura Gómez'][index]
    }
  };
});

const items = $input.all();
const results = [];

function normalizeSuggestedAction(parsedAction, intentScore) {
  const normalized = String(parsedAction || '').trim().toLowerCase();
  if (normalized === 'agendar' || normalized === 'nurture' || normalized === 'descartar') {
    return normalized;
  }
  if (intentScore >= 70) return 'agendar';
  if (intentScore >= 40) return 'nurture';
  return 'descartar';
}

for (const item of items) {
  const payload = {
    model: 'llama-3.3-70b-versatile',
    temperature: 0,
    max_tokens: 500,
    response_format: { type: 'json_object' },
    messages: [
      {
        role: 'system',
        content: 'You are a B2B sales qualification expert for Addi Marketplace. Return only valid JSON with intent_score, is_decision_maker, objection_type, suggested_action, reasoning. No markdown.'
      },
      {
        role: 'user',
        content: `Contexto:\nBrand: ${item.json.brand_id} (${item.json.category})\nGMV 12m: COP ${item.json.gmv_cop_millions_12m} MM\nMomentum: ${item.json.gmv_90d_to_12m_ratio}x\nScore Addi: ${item.json.final_score}\nContacto: ${item.json.contacto_nombre}\n\nReply recibido:\n${item.json.reply_text}\n\nClasifica segun intent_score (0-100), decision maker, objection type, y suggested action. Responde SOLO en JSON valido sin markdown.`
      }
    ]
  };

  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      Authorization: `Bearer ${$env.GROQ_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: payload,
    json: true
  });

  const content = data.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  const intentScore = Number.isFinite(Number(parsed.intent_score)) ? Number(parsed.intent_score) : 0;
  const suggestedAction = normalizeSuggestedAction(parsed.suggested_action, intentScore);
  const qualification_result = {
    intent_score: intentScore,
    is_decision_maker: parsed.is_decision_maker,
    objection_type: parsed.objection_type || null,
    suggested_action: suggestedAction,
    reasoning: parsed.reasoning || ''
  };

  results.push({
    json: {
      ...item.json,
      qualification_result,
      groq_raw: data
    }
  });
}

return results;

const items = $input.all();
const results = [];

function normalizeSuggestedAction(parsedAction, intentScore) {
  const normalized = String(parsedAction || '').trim().toLowerCase();
  if (normalized === 'agendar' || normalized === 'nurture' || normalized === 'descartar') {
    return normalized;
  }
  if (intentScore >= 70) return 'agendar';
  if (intentScore >= 40) return 'nurture';
  return 'descartar';
}

for (const item of items) {
  const intentScore = Number.isFinite(Number(item.json.qualification_result?.intent_score)) ? Number(item.json.qualification_result.intent_score) : 0;
  const routedAction = normalizeSuggestedAction(item.json.qualification_result?.suggested_action, intentScore);
  item.json.qualification_result.suggested_action = routedAction;

  if (routedAction === 'agendar') {
    const payload = {
      id: `DEMO_${String(item.json.brand_id || 'LEAD').replace(/[^A-Za-z0-9_]/g, '_')}_${Date.now()}`,
      FirstName: String(item.json.contacto_nombre || '').split(' ')[0] || '',
      LastName: String(item.json.contacto_nombre || '').split(' ').slice(1).join(' ').trim() || item.json.brand_id || 'Unknown',
      Company: item.json.brand_id || '',
      Email: item.json.contacto_email || '',
      LeadSource: 'Inbound - Addi Marketplace Motion',
      Status: 'Open - Not Contacted',
      xsell_score__c: item.json.final_score ?? null,
      bnpl_gmv_12m__c: item.json.gmv_cop_millions_12m ?? null,
      bnpl_momentum__c: item.json.gmv_90d_to_12m_ratio ?? null,
      cms_detected__c: item.json.cms_detectado || '',
      qualification_summary__c: item.json.qualification_result.reasoning,
      intent_score__c: item.json.qualification_result.intent_score,
      objection_type__c: item.json.qualification_result.objection_type,
      suggested_action__c: routedAction,
      linkedin_url__c: item.json.linkedin_url || '',
      enrichment_status__c: item.json.enrichment_status || 'success'
    };
    console.log(`[WF-5 Salesforce payload simulated] ${JSON.stringify(payload, null, 2)}`);
    item.json.salesforce_payload = payload;
    item.json.salesforce_lead_id = payload.id;
  }

  const slackBody = {
    text: 'DEMO: Caso procesado',
    blocks: [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Brand:* ${item.json.brand_id}\n*Scenario:* ${item.json.scenario}\n*Intent Score:* ${item.json.qualification_result.intent_score}/100\n*Suggested:* ${routedAction}\n*Objecion:* ${item.json.qualification_result.objection_type || 'Ninguna'}`
        }
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: item.json.qualification_result.reasoning
        }
      }
    ]
  };

  const slackResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: $env.SLACK_WEBHOOK_URL,
    headers: {
      'Content-Type': 'application/json'
    },
    body: slackBody,
    json: true
  });

  results.push({ json: { ...item.json, slack_status: 'sent', slack_response: slackResponse, routed_action: routedAction } });
}

return results;
